BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT ?req ?reqName ?child ?childType ?childName WHERE {
  ?req rdf:type vocab:tmt%20requirement .
  ?req vocab:NamedElement_name ?reqName .
  FILTER(
    CONTAINS(LCASE(STR(?reqName)), LCASE("interface")) &&
    CONTAINS(LCASE(STR(?reqName)), LCASE("require"))
  )
  OPTIONAL { ?child rdf:type ?childType }
  ?req vocab:Element_ownedElement ?child .
  OPTIONAL { ?child vocab:NamedElement_name ?childName }
}
LIMIT 25

BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT DISTINCT ?reqItem ?reqItemName ?slotName ?slotVal WHERE {
  ?ifaceReq rdf:type vocab:tmt%20requirement .
  ?ifaceReq vocab:NamedElement_name ?ifaceName .
  FILTER(CONTAINS(LCASE(STR(?ifaceName)), LCASE("interface")) && CONTAINS(LCASE(STR(?ifaceName)), LCASE("require")))

  ?ifaceReq vocab:Element_ownedElement+ ?reqItem .
  ?reqItem rdf:type vocab:instance%20specification .
  OPTIONAL { ?reqItem vocab:NamedElement_name ?reqItemName . }

  ?reqItem vocab:InstanceSpecification_slot ?slot .
  OPTIONAL { ?slot vocab:NamedElement_name ?slotName . }
  OPTIONAL { ?slot vocab:Slot_value ?slotVal . }
}
LIMIT 25

BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT DISTINCT ?reqItem ?reqItemName ?lit ?litVal WHERE {
  ?ifaceReq rdf:type vocab:tmt%20requirement .
  ?ifaceReq vocab:NamedElement_name ?ifaceName .
  FILTER(CONTAINS(LCASE(STR(?ifaceName)), LCASE("interface")) && CONTAINS(LCASE(STR(?ifaceName)), LCASE("require")))

  ?ifaceReq vocab:Element_ownedElement+ ?reqItem .
  ?reqItem rdf:type vocab:instance%20specification .
  OPTIONAL { ?reqItem vocab:NamedElement_name ?reqItemName . }

  ?reqItem vocab:InstanceSpecification_slot ?slot .
  ?slot vocab:Slot_value ?lit .
  OPTIONAL {
    ?lit rdf:type vocab:literal%20string .
    ?lit vocab:LiteralString_value ?litVal .
  }
  OPTIONAL {
    ?lit rdf:type vocab:instance%20value .
    ?lit vocab:InstanceValue_instance ?litVal .
  }
}
LIMIT 25

BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT DISTINCT ?reqItem ?reqItemName ?slotName ?slotVal WHERE {
  ?ifaceReq rdf:type vocab:tmt%20requirement .
  ?ifaceReq vocab:NamedElement_name ?ifaceName .
  FILTER(CONTAINS(LCASE(STR(?ifaceName)), LCASE("interface")) && CONTAINS(LCASE(STR(?ifaceName)), LCASE("require")))

  ?ifaceReq vocab:Element_ownedElement+ ?reqItem .
  ?reqItem rdf:type vocab:instance%20specification .
  OPTIONAL { ?reqItem vocab:NamedElement_name ?reqItemName . }

  ?reqItem vocab:InstanceSpecification_slot ?slot .
  OPTIONAL { ?slot vocab:NamedElement_name ?slotName . }
  OPTIONAL {
    ?slot vocab:Slot_value ?lit .
    OPTIONAL {
      ?lit rdf:type vocab:literal%20string .
      ?lit vocab:LiteralString_value ?slotVal .
    }
    OPTIONAL {
      ?lit rdf:type vocab:instance%20value .
      ?lit vocab:InstanceValue_instance ?slotVal .
    }
    OPTIONAL {
      ?slot vocab:Slot_value ?slotVal .
    }
  }
  FILTER(
    CONTAINS(LCASE(STR(?slotName)), "status") ||
    CONTAINS(LCASE(STR(?slotName)), "accept") ||
    CONTAINS(LCASE(STR(?slotName)), "verified") ||
    CONTAINS(LCASE(STR(?slotName)), "maturity") ||
    CONTAINS(LCASE(STR(?slotVal)), "accept") ||
    CONTAINS(LCASE(STR(?slotVal)), "approved") ||
    CONTAINS(LCASE(STR(?slotVal)), "rejected") ||
    CONTAINS(LCASE(STR(?slotVal)), "pending") ||
    CONTAINS(LCASE(STR(?slotVal)), "verified") ||
    CONTAINS(LCASE(STR(?slotVal)), "maturity")
  )
}
LIMIT 25
